// Extract grants from Grants.gov search2 API response
const items = $input.all();
const grants = [];

for (const item of items) {
  const response = item.json;

  let oppHits = [];
  if (response.data && response.data.oppHits) {
    oppHits = response.data.oppHits;
  } else if (response.oppHits) {
    oppHits = response.oppHits;
  } else if (Array.isArray(response)) {
    oppHits = response;
  }

  for (const opp of oppHits) {
    if (!opp || !opp.title) continue;

    const oppNum = opp.number || opp.opportunityNumber || 'GG-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);

    grants.push({
      json: {
        id: opp.id || opp.opportunityId,
        oppNum: oppNum,
        title: opp.title,
        description: opp.synopsis || opp.description || '',
        link: 'https://www.grants.gov/search-results-detail/' + (opp.id || opp.opportunityId),
        openDate: opp.openDate || opp.postedDate || '',
        closeDate: opp.closeDate || 'See listing',
        agency: opp.agency || opp.agencyName || '',
        agencyCode: opp.agencyCode || '',
        category: opp.category || '',
        source: 'Grants.gov',
        awardFloor: parseInt(opp.awardFloor) || 0,
        awardCeiling: parseInt(opp.awardCeiling) || 0,
        status: opp.oppStatus || opp.status || ''
      }
    });
  }
}

return grants.length > 0 ? grants : [{ json: { empty: true, source: 'grants.gov' } }];

