// n8n Code node – Extract ALL data from "Upcoming Funding Opportunity" section on RWJF page

const items = $input.all();
const results = [];

for (const item of items) {
  // Get HTML from common n8n HTTP Response locations
  let html = item.json?.body || item.json?.data || item.json?.html || item.json || "";
  if (typeof html !== 'string' || html.length < 500) {
    results.push({
      json: {
        error: "No valid HTML received",
        receivedType: typeof html,
        length: html?.length || 0
      }
    });
    continue;
  }

  // Normalize whitespace and remove script/style tags to make regex more reliable
  html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
             .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
             .replace(/\s+/g, ' ');

  // Find the "Upcoming Funding Opportunity" heading and grab content until next major section
  // We look for the h3/p with "Upcoming" then the following card with h4 + paragraphs
  const sectionRegex = /<h3[^>]*>Active Funding Opportunities<\/h3>[\s\S]*?<p[^>]*><span[^>]*>Upcoming Funding Opportunity<\/span><\/p>[\s\S]*?(<div class="card image[^>]*>[\s\S]*?<div class="cmp-customcard[^>]*>[\s\S]*?<\/div>)/i;

  const sectionMatch = sectionRegex.exec(html);
  if (!sectionMatch) {
    results.push({
      json: {
        empty: true,
        message: "No 'Upcoming Funding Opportunity' section found in HTML",
        hint: "Content may be loaded dynamically via JavaScript → check Network tab for JSON calls"
      }
    });
    continue;
  }

  const cardHtml = sectionMatch[1];

  // Extract title (h4 with heading8-style or similar)
  const titleMatch = cardHtml.match(/<h4[^>]*class="[^"]*heading8-style[^"]*"[^>]*>([\s\S]*?)<\/h4>/i);
  const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : "No title found";

  // Extract all <p> paragraphs in the card (description + release date)
  const descParagraphs = [];
  const pRegex = /<p[^>]*>([\s\S]*?)<\/p>/gi;
  let pMatch;
  while ((pMatch = pRegex.exec(cardHtml)) !== null) {
    let text = pMatch[1]
      .replace(/<[^>]+>/g, '')          // strip inner tags
      .replace(/&nbsp;/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    if (text && text.length > 10) {      // ignore very short/empty
      descParagraphs.push(text);
    }
  }

  // Look for bold release date specifically
  const releaseMatch = cardHtml.match(/<b>Release date:\s*([^<]+)<\/b>/i);
  const releaseDate = releaseMatch ? releaseMatch[1].trim() : "Not found";

  // Build clean output
  results.push({
    json: {
      section: "Upcoming Funding Opportunity",
      title: title,
      releaseDate: releaseDate,
      description: descParagraphs.join("\n\n"),  // full text, paragraphs separated
      sourceUrl: "https://www.rwjf.org/en/grants/active-funding-opportunities.html",
      scrapedAt: new Date().toISOString(),
      note: "This is the static upcoming card. Active/open opportunities load via JS → see Network tab for JSON endpoint if you need more."
    }
  });
}

// If nothing was found at all
if (results.length === 0) {
  results.push({
    json: {
      empty: true,
      message: "No upcoming opportunity data extracted"
    }
  });
}

return results;

const items = $input.all();
const results = [];

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1/grants';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

for (const item of items) {
  const grant = item.json;
  const oppNum = (grant.oppNum || '').trim();
  const title = (grant.title || '').trim();

  // Skip if no identifier at all
  if (!oppNum && !title) continue;

  let response;
  try {
    // Check by source_id (where oppNum is stored) first, fall back to title match
    const queryParam = oppNum
      ? `source_id=eq.${encodeURIComponent(oppNum)}`
      : `title=eq.${encodeURIComponent(title)}`;

    response = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}?${queryParam}&select=id,source_id,title`,
      headers: {
        'apikey': supabaseKey,
        'Authorization': 'Bearer ' + supabaseKey,
      },
    });
  } catch (e) {
    // If fetch fails, include it so it can be retried manually
    results.push({
      json: {
        grant,
        newGrants: true,
        status: 'error',
        message: e.message,
      },
    });
    continue;
  }

  if (!Array.isArray(response)) {
    results.push({
      json: {
        grant,
        newGrants: true,
        status: 'invalid response',
        message: 'Unexpected Supabase response',
        rawResponse: response,
      },
    });
    continue;
  }

  if (response.length === 0) {
    // Only push NEW grants downstream
    results.push({
      json: {
        grant,
        newGrants: true,
        status: 'new',
        message: 'Grant not found in Supabase, will be added',
      },
    });
  }
  // Grants that already exist are silently filtered out
}

// If no new grants found
if (results.length === 0) {
  return [{ json: { newGrants: false, noNewGrants: true, message: 'All grants already tracked' } }];
}

return results;

const aiText = $input.first().json?.output?.[0]?.content?.[0]?.text
  || $input.first().json?.text
  || '[]';

// Parse the array of IDs from the AI
let keepIds = [];
try {
  const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  keepIds = JSON.parse(cleaned);
} catch (e) {
  // If parsing fails, keep everything rather than dropping all
  keepIds = null;
}

// Get the original grant items from before the AI node
const originalItems = $('Status: Matching').all();

const results = [];
for (const item of originalItems) {
  const grant = item.json.grant || item.json;
  const grantId = grant.id || grant.source_id || '';

  // If parsing failed (keepIds is null), keep all grants
  if (keepIds !== null && !keepIds.includes(String(grantId))) {
    continue; // AI said to discard this one
  }

  results.push({
    json: {
      grant,
      org_id: item.json.org_id,
      location_filter_reason: item.json.location_filter_reason || '',
      newGrants: true,
      status: 'new',
      hasResults: true,
    }
  });
}

if (results.length === 0) {
  return [{ json: { noRelevantGrants: true, message: 'No grants matched your search filters', hasResults: false } }];
}

return results;

