  const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';
  const headers = {
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal',
  };

  const d = item;
  const grant = d.grant || d;

  if (grant && grant.title) {
    const transformed = {
      title: grant.title || '',
      funder_name: grant.agency || grant.funder_name || 'Unknown',
      description: grant.description || '',
      amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
      deadline: grant.closeDate && grant.closeDate !== 'See listing' ? grant.closeDate : null,
      stage: 'discovery',
      source: grant.source || 'Grants.gov',
      source_id: grant.id || grant.oppNum || null,
      source_url: grant.link || grant.source_url || null,
      org_id: orgId,
      metadata: {
        grants_gov_id: grant.id,
        agency_code: grant.agencyCode,
        open_date: grant.openDate,
        award_floor: grant.awardFloor,
        award_ceiling: grant.awardCeiling,
        priority: 'medium',
      },
    };

    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl,
      headers,
      body: JSON.stringify({
        search_id: searchId,
        org_id: orgId,
        source_group: 'grant_search',
        grant_data: [transformed],
        is_complete: false,
      }),
    });

    return [{ json: { success: true, grant_saved: transformed.title } }];
  }

  return [{ json: { success: false, grant_saved: 'none' } }];

